package com.oossync.chat\n\nimport android.Manifest\nimport android.content.pm.PackageManager\nimport android.os.Bundle\nimport android.provider.ContactsContract\nimport androidx.appcompat.app.AppCompatActivity\nimport androidx.core.app.ActivityCompat\nimport androidx.core.content.ContextCompat\nimport androidx.recyclerview.widget.LinearLayoutManager\nimport androidx.recyclerview.widget.RecyclerView\n\nclass MainActivity : AppCompatActivity() {\n    private val contactsList = mutableListOf<String>()\n    private lateinit var recyclerView: RecyclerView\n    private lateinit var adapter: ContactsAdapter\n\n    override fun onCreate(savedInstanceState: Bundle?) {\n        super.onCreate(savedInstanceState)\n        setContentView(R.layout.activity_main)\n        recyclerView = findViewById(R.id.recycler_view)\n        recyclerView.layoutManager = LinearLayoutManager(this)\n        adapter = ContactsAdapter(contactsList)\n        recyclerView.adapter = adapter\n        checkPermissionsAndLoadContacts()\n    }\n\n    private fun checkPermissionsAndLoadContacts() {\n        if (ContextCompat.checkSelfPermission(this, Manifest.permission.READ_CONTACTS) != PackageManager.PERMISSION_GRANTED) {\n            ActivityCompat.requestPermissions(this, arrayOf(Manifest.permission.READ_CONTACTS), 1)\n        } else {\n            loadContacts()\n        }\n    }\n\n    private fun loadContacts() {\n        val cursor = contentResolver.query(ContactsContract.CommonDataKinds.Phone.CONTENT_URI, null, null, null, null)\n        cursor?.let { c ->\n            while (c.moveToNext()) {\n                val name = c.getString(c.getColumnIndex(ContactsContract.CommonDataKinds.Phone.DISPLAY_NAME))\n                contactsList.add(name)\n            }\n            c.close()\n        }\n        adapter.notifyDataSetChanged()\n    }\n}\n\nclass ContactsAdapter(private val contacts: List<String>) : RecyclerView.Adapter<ContactsAdapter.ContactsViewHolder>() {\n    class ContactsViewHolder(val view: androidx.recyclerview.widget.RecyclerView) : RecyclerView.ViewHolder(view) {\n        // Bind the contact data to the view here\n    }\n\n    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): ContactsViewHolder {\n        // Inflate your view for each item here\n    }\n\n    override fun onBindViewHolder(holder: ContactsViewHolder, position: Int) {\n        // Bind data to the item in your view here\n    }\n\n    override fun getItemCount() = contacts.size\n}